<template>
  <div style="padding:20px;">
    <Spin fix v-if="loadingshow" >
      <Icon type="ios-loading" size=18 class="demo-spin-icon-load"></Icon>
      <div>正在加载....</div>
    </Spin>
    <div><h1>人员信息管理</h1></div><br/>
    <div style="width:250px;float:left">
      <Input type="text" v-model="useraccount" placeholder="请输入人员账号" style="width:180px"/>
      <Button shape="circle" icon="ios-search" @click="search"></Button>
    </div>
    <Button type="primary"  @click="insertWindowopen()" style="float:right">添加用户</Button><br/><br/><br/>
    <Table stripe :columns="columns1" :data="dataview"></Table><br/><br/><br/>
    <Page :total="pagedata.count"
          :current="pagedata.currentPage"
          :page-size="pagedata.pageSize"
          show-elevator
          show-total
          @on-change="handlePage"></Page>
    <!--添加用户弹窗-->
    <el-dialog title="添加用户" :visible.sync="insertVisible" width="700px">
      <el-form :model="insertform" >
        <!--<el-form-item label="用户名称" :label-width="formLabelWidth" >-->
          <!--<el-input v-model="insertform.user_name"  autocomplete="off"></el-input>-->
        <!--</el-form-item>-->
        <el-form-item label="用户账号" :label-width="formLabelWidth" style="text-align: center">
          <el-input v-model="insertform.account" autocomplete="off"></el-input>
        </el-form-item>
        <el-form-item label="密码" :label-width="formLabelWidth" style="text-align: center">
          <el-input v-model="insertform.password" autocomplete="off"></el-input>
        </el-form-item>
        <!--<el-form-item label="手机号" :label-width="formLabelWidth">-->
          <!--<el-input v-model="insertform.user_phone" autocomplete="off"></el-input>-->
        <!--</el-form-item>-->
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="insertVisible = false">取 消</el-button >
        <el-button type="primary" @click="insertuser">确 定</el-button>
      </div>
    </el-dialog>
    <!--更新用户弹窗-->
    <el-dialog  title="密码修改" :visible.sync="updateVisible"  width="700px">
      <el-form :model="updateform" >
        <el-form-item label="用户账号" :label-width="formLabelWidth">
          <el-input v-model="updateform.account" autocomplete="off" readonly=""></el-input>
        </el-form-item>
        <el-form-item label="用户密码" :label-width="formLabelWidth" >
          <el-input v-model="updateform.user_name"  autocomplete="off"></el-input>
        </el-form-item>
        <!--<el-form-item label="手机号" :label-width="formLabelWidth">-->
          <!--<el-input v-model="updateform.user_phone" autocomplete="off"></el-input>-->
        <!--</el-form-item>-->
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="updateVisible = false">取 消</el-button>
        <el-button type="primary" @click="updateuser">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
  import  api from '../../API/api'
  export default {
    name: "userpage",
    data () {
      return {
        useraccount:'',             //前端获取数据
        userInfoObj: {},            //后端返回的数据储存在这里
        insertform: {},             //添加人员的model
        updateform: {},             //更新人员的model
        insertVisible: false,       //添加人员弹框默认隐藏
        updateVisible: false,       //更新用户弹框默认隐藏
        formLabelWidth   : '80px',   //弹框标签的大小
        pagedata   :{},              //后台发送的分页数据包含count数据总条数;totalPages页面总数;pageSize单页面数据量;currentPage当前页面的页数
        sendpage:"1",                //初始的发送页
        loadingshow: false,          //加载动画
        dataview:[] ,      //将userInfoObj中的内容重新赋给dataview并显示在表格
        columns1:[
          {
            title: '序号',
            type  : 'index'
          },
          {
            title: '用户账号',
            key  : 'account'
          },
          {
            title: '用户密码',
            key  : 'password'
          },
          {
            title : '操作',
            key   : 'action',
            width : 300,
            align : 'center',
            render: (h, params) => {
              return h('div', [
                h('Button', {
                  props: {
                    type: 'success',
                    size: 'large'
                  },
                  style: {
                    marginRight: '5px'
                  },
                  on: {
                    click: () => {
                      this.updateWindowopen(params.row)
                    }
                  }
                }, '编辑'),
                h('Button', {
                  props: {
                    type: 'error',
                    size: 'large'
                  },
                  on: {
                    click: () => {
                      this.deleteuser(params.row.account)
                    }
                  }
                }, '删除')
              ]);
            }
          }

        ],                //定义表格列

      }
    },
    //查看所有用户
    created:function(){
      this.selectalluser();
      this.loadingshow= true;
      setTimeout(() => {
        this.loadingshow= false;
      }, 1000);
    },
    methods: {
      //从UI组件的取值，获取当前页
      handlePage(value) {
        this.sendpage = value;
        this.selectalluser();
      },
      //查看所有用户
      selectalluser: function(){
        this.$Loading.start();       //设置进度条开始数据加载
        let data = {
          currentPage : this.sendpage,
        };
        this.$http.post(api.apiConfig.user.selectuser,data)
          .then(res => {
            console.log(res,'res');
            console.log(res.data,'res.data');
            console.log(res.data.data,'res.data.data');
            if (res.data.errno === 0) {
              setTimeout(() => {
                this.pagedata = res.data.data;//后端发送的分页信息
                this.dataview = res.data.data.data;//用户信息保存在dataview中并显示
                this.loadingshow = false;        //关闭加载动画
                this.$Loading.finish();      //数据加载完成
                this.$Message.success("查询用户成功");
              }, 1000);
            }else if(res.data.errno === 404){
              this.$Loading.error();       //数据加载错误
              this.$Message.warning('token不存在或不匹配，请重新登录！')
            } else {
              this.$Loading.error();       //数据加载错误
              this.$Message.error("查询用户失败")
            }
          }).catch(err => {
          this.$Loading.error();       //数据加载错误
          this.$Message.error("服务器错误")
        })
      },
      //超级管理员删除用户
      deleteuser(code){
        console.log('code',code);
        this.$Modal.confirm({
          title  : '确认删除用户？',
          content: '<p>删除后将无法撤回</p>',
          onOk   : () => {
            // this.$http.delete(api.apiConfig.user.remove,{
            //   params:{account: code}
            // })
            let data = {
              account : code
            };
            this.$http.post(api.apiConfig.user.remove,data)
              .then(res =>
              {
                console.log("res",res);
                if (res.data.errno === 0) {
                  this.selectalluser();  //重新查询数据库
                  this.$Message.success("删除用户成功");
                } else {
                  this.$Message.error("删除用户失败")
                }
              }).catch(err => {
              this.$Message.error("服务器错误")
            })
          },
          onCancel: () => {
          }
        });
      },
      //申请添加用户
      insertWindowopen: function () {
        this.insertVisible = true;
      },
      //提交用户信息
      insertuser:function(){
        let data = {
          account                : this.insertform.account,
          password               : this.insertform.password,
          // password               : this.$md5(this.insertform.password+""),
        };
        console.log(data,'添加用户数据');
        this.$http.post(api.apiConfig.user.adduser,data).then(
          res=>{
            console.log(res.data);
            if(res.data.errno===0){
              console.log("添加用户成功");
              this.sendpage= '1';        //页码重置为1
              this.selectalluser();      //重新查询数据库
              this.insertVisible = false;  //关闭弹窗
              this.insertform.account = "";//数据置空
                this.insertform.password = ""; //数据置空
              this.$Message.success('添加用户成功');
            }else if(res.data.errno===300){
              this.insertVisible = false;  //关闭弹窗
              this.$Message.warning('账号已经存在！');
            }else if(res.data.errno===505){
              this.insertVisible = false;  //关闭弹窗
              this.$Message.warning('缺少参数，账号或密码非法');
            }
          },
          err=>{
            console.log("服务器错误！");
          })
      },
      //申请更新用户
      updateWindowopen: function (editparams) {
        this.updateVisible = true;
        this.updateform    = editparams;//将原来信息显示在修改表格中
      },
      //提交更新信息
      updateuser: function () {
        let data = {
          account                : this.updateform.account,
          password               : this.updateform.password,
        };
        this.$http.put(api.apiConfig.user.upuser,data).then(
          res=>{
            if(res.data.errno===0){
              this.updateVisible = false;  //关闭弹窗
              this.$Message.success('信息修改成功');

            }else if(res.data.errno===505){
              this.$Message.warning('密码非法！');
              this.updateVisible = false;  //关闭弹窗
            }else if (res.data.errno===100){
              this.$Message.warning('没有该用户！');
              this.updateVisible = false;  //关闭弹窗
            } else{
              this.$Message.warning('修改失败未知错误！');
              this.updateVisible = false;  //关闭弹窗
            }
          },
          err=>{
            console.log("服务器错误！");
          })
      },
      //查找单个人员
      search(){
        let data = {
          account : this.useraccount
        }
        this.$http.post(api.apiConfig.user.finduser,data)
          .then(res => {
            console.log(data,'data')
            console.log(res,'返回')
            if (res.data.errno === 0) {
              this.userInfoObj = res.data.data;
              console.log(res.data.data,'res.data.data')
              this.$Message.success("查找用户成功");
              this.$Modal.info({
                title  : '人员信息详情',
                content:
                  `用户账号：${this.userInfoObj.account}<br>
                  用户密码：${this.userInfoObj.password}`
              })
            } else if (res.data.errno === 100){
              this.$Message.warning("用户不存在")
            }else if(res.data.errno === 505){
              this.$Message.warning("缺少参数")
            }
          }).catch(err => {
          this.$Message.error("服务器错误")
        })
      },
    }
  }
</script>

<style scoped>
  .demo-spin-col{
    height: 100px;
    position: relative;
    border: 1px solid #eee;
  }
</style>



